// BTEmptyState — types & per-variant defaults.
// Figma node 3688:2647 — 7 variants.

import 'package:flutter/material.dart';

/// Visual variant of BTEmptyState.
enum BTEmptyStateVariant {
  /// 400 Bad Request — file icon + X badge. Button: "Reload".
  e400,

  /// 401 Unauthorized — person + lock card + ! badge. Button: "Go Back".
  e401,

  /// 404 Not Found — browser + search icon + ! badge. Button: "Go Back".
  e404,

  /// 500 Server Error — list cards + ! badge. Button: "Reload".
  e500,

  /// Under Maintenance — browser + wrench icon + ! badge. Button: "Go Back".
  underMaintenance,

  /// No Data — small file illustration. No button.
  noData,

  /// No Result — small search circles. No button.
  noResult,
}

/// Per-variant default content (error variants only).
class BTEmptyStateDefaults {
  const BTEmptyStateDefaults({
    required this.title,
    required this.subtext,
    required this.errorMessage,
    required this.buttonLabel,
    required this.assetLight,
    required this.assetDark,
  });

  final String title;
  final String subtext;
  final String errorMessage;
  final String buttonLabel;

  /// Illustration shown in light theme.
  final String assetLight;

  /// Illustration shown in dark theme.
  final String assetDark;

  /// Resolve the illustration for the current [brightness].
  String assetFor(Brightness brightness) =>
      brightness == Brightness.dark ? assetDark : assetLight;
}

/// Default content map keyed by variant.
const Map<BTEmptyStateVariant, BTEmptyStateDefaults> kEmptyStateDefaults = {
  BTEmptyStateVariant.e400: BTEmptyStateDefaults(
    title: 'Oops! Something Went Wrong',
    subtext: "We couldn't process your request. Please try again later.",
    errorMessage: 'Error : System Message',
    buttonLabel: 'Reload',
    assetLight: 'packages/btech_assets/assets/illus/illus-400-light.svg',
    assetDark: 'packages/btech_assets/assets/illus/illus-400-dark.svg',
  ),
  BTEmptyStateVariant.e401: BTEmptyStateDefaults(
    title: 'No Unauthorized Access',
    subtext:
        "We couldn't verify your credentials. Please check your login details and try again.",
    errorMessage: 'Error : System Message',
    buttonLabel: 'Go Back',
    assetLight: 'packages/btech_assets/assets/illus/illus-401-light.svg',
    assetDark: 'packages/btech_assets/assets/illus/illus-401-dark.svg',
  ),
  BTEmptyStateVariant.e404: BTEmptyStateDefaults(
    title: "This Page isn't Available",
    subtext:
        "We couldn't find the page you're looking for. It may have been moved or no longer exists.",
    errorMessage: 'Error : System Message',
    buttonLabel: 'Go Back',
    assetLight: 'packages/btech_assets/assets/illus/illus-404-light.svg',
    assetDark: 'packages/btech_assets/assets/illus/illus-404-dark.svg',
  ),
  BTEmptyStateVariant.e500: BTEmptyStateDefaults(
    title: "This Page Isn't Working",
    subtext:
        'We apologize for the inconvenience, we are currently working on repairs. Please return in a moment.',
    errorMessage: 'Error : System Message',
    buttonLabel: 'Reload',
    assetLight: 'packages/btech_assets/assets/illus/illus-500-light.svg',
    assetDark: 'packages/btech_assets/assets/illus/illus-500-dark.svg',
  ),
  BTEmptyStateVariant.underMaintenance: BTEmptyStateDefaults(
    title: 'This Page Is Under Maintenance',
    subtext:
        'We are improving this page, and will be back soon! You can explore other page.',
    errorMessage: 'Error : System Message',
    buttonLabel: 'Go Back',
    assetLight: 'packages/btech_assets/assets/illus/illus-maintenance-light.svg',
    assetDark: 'packages/btech_assets/assets/illus/illus-maintenance-dark.svg',
  ),
  BTEmptyStateVariant.noData: BTEmptyStateDefaults(
    title: '',
    subtext: "There's no data yet.",
    errorMessage: '',
    buttonLabel: '',
    assetLight: 'packages/btech_assets/assets/illus/illus-no-data-light.svg',
    assetDark: 'packages/btech_assets/assets/illus/illus-no-data-dark.svg',
  ),
  BTEmptyStateVariant.noResult: BTEmptyStateDefaults(
    title: '',
    subtext: 'No result found.',
    errorMessage: '',
    buttonLabel: '',
    assetLight: 'packages/btech_assets/assets/illus/illus-no-result-light.svg',
    assetDark: 'packages/btech_assets/assets/illus/illus-no-result-dark.svg',
  ),
};

/// Error variants — full layout with title + subtext + error message + optional button.
const Set<BTEmptyStateVariant> kErrorVariants = {
  BTEmptyStateVariant.e400,
  BTEmptyStateVariant.e401,
  BTEmptyStateVariant.e404,
  BTEmptyStateVariant.e500,
  BTEmptyStateVariant.underMaintenance,
};

/// BTEmptyState — empty / error state organism.
///
/// Figma: node 3730:1710 (Mobile) — 7 variants.
/// Mobile spec: illustration 180dp, title subheading/h7 (14px bold),
/// text block padded 24dp horizontal, button full-width.
///
/// ## Usage
/// ```dart
/// // Error variant — full layout
/// BTEmptyState(
///   variant: BTEmptyStateVariant.e404,
///   onButtonPressed: () => Navigator.pop(context),
/// )
///
/// // Override texts
/// BTEmptyState(
///   variant: BTEmptyStateVariant.e500,
///   title: 'Custom Title',
///   subtext: 'Custom subtext',
///   buttonLabel: 'Try Again',
///   onButtonPressed: () => retry(),
/// )
///
/// // Hide button
/// BTEmptyState(
///   variant: BTEmptyStateVariant.e400,
///   showButton: false,
/// )
///
/// // Simple variants — no button
/// BTEmptyState(variant: BTEmptyStateVariant.noData)
/// BTEmptyState(variant: BTEmptyStateVariant.noResult)
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../button/button.types.dart';
import '../button/button.widget.dart';
import 'package:btech_ui/src/components/organisms/empty_state/empty_state.types.dart';
import 'package:flutter/material.dart';
import 'package:flutter_svg/flutter_svg.dart';

/// Empty / error state organism. See file header for usage.
class BTEmptyState extends StatelessWidget {
  const BTEmptyState({
    required this.variant,
    this.title,
    this.subtext,
    this.errorMessage,
    this.buttonLabel,
    this.showButton = true,
    this.onButtonPressed,
    super.key,
  });

  /// Visual variant. Determines illustration, layout size, and default texts.
  final BTEmptyStateVariant variant;

  /// Override title (error variants only). Defaults to per-variant Figma value.
  final String? title;

  /// Override subtext. Defaults to per-variant Figma value.
  final String? subtext;

  /// Override error/system message (error variants only).
  /// Default: 'Error : System Message'.
  final String? errorMessage;

  /// Override button label (error variants only).
  /// Default: 'Reload' or 'Go Back' per variant.
  final String? buttonLabel;

  /// Show the action button (error variants only).
  /// Always false for [BTEmptyStateVariant.noData] and [BTEmptyStateVariant.noResult].
  /// @default true
  final bool showButton;

  /// Callback fired when the action button is tapped.
  final VoidCallback? onButtonPressed;

  // ── Helpers ───────────────────────────────────────────────────────────────

  bool get _isError => kErrorVariants.contains(variant);

  BTEmptyStateDefaults get _defaults => kEmptyStateDefaults[variant]!;

  String get _title       => title        ?? _defaults.title;
  String get _subtext     => subtext      ?? _defaults.subtext;
  String get _errorMsg    => errorMessage ?? _defaults.errorMessage;
  String get _buttonLabel => buttonLabel  ?? _defaults.buttonLabel;
  bool   get _showButton  => _isError && showButton;

  // ── Build ─────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    return _isError ? _buildErrorLayout(context) : _buildSimpleLayout(context);
  }

  // ── Error variant layout ─────────────────────────────────────────────────
  // Mobile spec (3730:1710):
  //   • illustration  : 180×180 dp
  //   • gap (illus→text): spacing.md = 12 dp
  //   • text wrapper  : px = spacing.xl = 24 dp
  //   • gap (between texts): spacing.md = 12 dp
  //   • title         : subheading/h7 — 14 sp bold, lineHeight.xs (16/14)
  //   • subtext       : body/regular  — 14 sp w500, lineHeight.xs (16/14)
  //   • error msg     : body/regular  — 14 sp w500, lineHeight.xs (16/14)
  //   • button        : full-width, secondaryLight, size sm
  Widget _buildErrorLayout(BuildContext context) {
    final colors = context.btColor;

    return SizedBox(
      width: double.infinity,
      child: Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.center,
        children: [
          // Illustration — 180×180 dp (mobile spec).
          // Theme-aware: light/dark SVG chosen from the active brightness.
          SvgPicture.asset(
            _defaults.assetFor(Theme.of(context).brightness),
            width: 180,
            height: 180,
            fit: BoxFit.contain,
          ),

          // spacing.md = 12 dp between illustration and text wrapper
          const SizedBox(height: 12),

          // Text wrapper — px: spacing.xl = 24 dp
          Padding(
            padding: const EdgeInsets.symmetric(horizontal: 24),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.center,
              children: [
                // Title — subheading/h7: 14 sp bold, lineHeight.xs (16/14)
                Text(
                  _title,
                  textAlign: TextAlign.center,
                  style: TextStyle(
                    fontFamily: BTTypography.fontFamily,
                    fontSize: 14,
                    fontWeight: FontWeight.w700,
                    height: 16 / 14,
                    letterSpacing: 0,
                    color: colors.text.primary,
                  ),
                ),
                // spacing.md = 12 dp between texts
                const SizedBox(height: 12),

                // Subtext — body/regular: 14 sp w500, lineHeight.xs
                Text(
                  _subtext,
                  textAlign: TextAlign.center,
                  style: TextStyle(
                    fontFamily: BTTypography.fontFamily,
                    fontSize: 14,
                    fontWeight: FontWeight.w500,
                    height: 16 / 14,
                    letterSpacing: 0,
                    color: colors.text.secondary,
                  ),
                ),
                const SizedBox(height: 12),

                // Error/system message — body/regular: 14 sp w500, lineHeight.xs
                Text(
                  _errorMsg,
                  textAlign: TextAlign.center,
                  style: TextStyle(
                    fontFamily: BTTypography.fontFamily,
                    fontSize: 14,
                    fontWeight: FontWeight.w500,
                    height: 16 / 14,
                    letterSpacing: 0,
                    color: colors.text.tertiary,
                  ),
                ),
              ],
            ),
          ),

          // Button — full width, spacing.md = 12 dp gap
          if (_showButton) ...[
            const SizedBox(height: 12),
            // BTButton is intrinsic-width; SizedBox forces full width
            SizedBox(
              width: double.infinity,
              child: BTButton(
                label: _buttonLabel,
                variant: BTButtonVariant.secondaryLight,
                size: BTButtonSize.sm,
                onPressed: onButtonPressed,
              ),
            ),
          ],
        ],
      ),
    );
  }

  // ── Simple variant layout ─────────────────────────────────────────────────
  // Mobile spec: p = spacing.sm = 8 dp, gap = spacing.lg = 16 dp
  //   • illustration: 92×98 dp (unchanged)
  //   • label: body/regular — 14 sp w500, lineHeight.xs (16/14)
  Widget _buildSimpleLayout(BuildContext context) {
    final colors = context.btColor;

    return Padding(
      padding: const EdgeInsets.all(8), // spacing.sm
      child: Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.center,
        children: [
          // Illustration — 92×98 dp.
          // Theme-aware: light/dark SVG chosen from the active brightness.
          SvgPicture.asset(
            _defaults.assetFor(Theme.of(context).brightness),
            width: 92,
            height: 98,
            fit: BoxFit.contain,
          ),
          // spacing.lg = 16 dp
          const SizedBox(height: 16),

          // Label — body/regular: 14 sp w500, lineHeight.xs (16/14)
          Text(
            _subtext,
            textAlign: TextAlign.center,
            style: TextStyle(
              fontFamily: BTTypography.fontFamily,
              fontSize: 14,
              fontWeight: FontWeight.w500,
              height: 16 / 14,
              letterSpacing: 0,
              color: colors.text.secondary,
            ),
          ),
        ],
      ),
    );
  }
}
